        hv_obj = pg.hypervolume(selected)
        hv = hv_obj.compute(reference_point)
        hv_cache[key] = hv
        return hv

    def marginal_contribution(S: Set[int], p: int) -> float:
        """Compute marginal contribution of point p to set S"""
        if p in S:
            S_without = S - {p}
            return compute_hv(S) - compute_hv(S_without)
        else:
            S_with = S | {p}
            return compute_hv(S_with) - compute_hv(S)

    # Pareto archive: store solutions of different sizes
    pareto_archive: Dict[int, Set[int]] = {}

    # 1. Greedy initialization
    def greedy_initialization() -> Set[int]:
        """Fast greedy construction using marginal contributions"""
        current_set = set()

        for _ in range(k):
            best_idx = -1
            best_contrib = -float('inf')

            for idx in range(n):
                if idx in current_set:
                    continue
                contrib = marginal_contribution(current_set, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx

            if best_idx != -1:
                current_set.add(best_idx)

        pareto_archive[k] = current_set
        return current_set

    # 2. Evolutionary search with adaptive mutation
    def evolutionary_search(base_solution: Set[int], generations: int = 15) -> Set[int]:
        """Evolutionary search with size-biased mutation"""
        population_size = 10
        population: List[Set[int]] = [base_solution.copy()]
        population_hv = [compute_hv(base_solution)]

        # Initialize population with mutated solutions
        for i in range(population_size - 1):
            mutated = base_solution.copy()

            # Adaptive mutation rate based on size deviation
            current_size = len(mutated)
            size_deviation = abs(current_size - k) / k
            mutation_rate = 0.4 * (1 - size_deviation)  # Higher rate when size is far from k

            if random.random() < mutation_rate:
                # Biased mutation: remove worst, add best by contribution
                if len(mutated) > 0:
                    # Remove worst point
                    worst_contrib = float('inf')
                    worst_idx = None
                    for idx in mutated:
                        contrib = marginal_contribution(mutated - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        mutated.remove(worst_idx)

                # Add best point
                best_contrib = -float('inf')
                best_idx = None
                for idx in range(n):
                    if idx not in mutated:
                        contrib = marginal_contribution(mutated, idx)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_idx = idx

                if best_idx is not None:
                    mutated.add(best_idx)

            # Ensure size is exactly k
            while len(mutated) > k:
                # Remove point with smallest contribution
                smallest_contrib = float('inf')
                remove_idx = None
                for idx in mutated:
                    contrib = marginal_contribution(mutated - {idx}, idx)
                    if contrib < smallest_contrib:
                        smallest_contrib = contrib
                        remove_idx = idx

                if remove_idx is not None:
                    mutated.remove(remove_idx)

            while len(mutated) < k:
                # Add point with largest contribution
                largest_contrib = -float('inf')
                add_idx = None
                for idx in range(n):
                    if idx not in mutated:
                        contrib = marginal_contribution(mutated, idx)
                        if contrib > largest_contrib:
                            largest_contrib = contrib
                            add_idx = idx

                if add_idx is not None:
                    mutated.add(add_idx)

            population.append(mutated)
            population_hv.append(compute_hv(mutated))

        # Evolutionary generations
        for gen in range(generations):
            # Tournament selection
            tournament_indices = random.sample(range(population_size), 3)
            parent_idx = tournament_indices[0]
            for idx in tournament_indices:
                if population_hv[idx] > population_hv[parent_idx]:
                    parent_idx = idx

            parent = population[parent_idx]

            # Create offspring with size-biased mutation
            offspring = parent.copy()
            current_size = len(offspring)
            size_deviation = abs(current_size - k) / k
            mutation_rate = 0.3 * (1 - size_deviation)

            if random.random() < mutation_rate:
                # Contribution-guided swap
                if len(offspring) > 0:
                    # Remove worst
                    worst_contrib = float('inf')
                    worst_idx = None
                    for idx in offspring:
                        contrib = marginal_contribution(offspring - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        offspring.remove(worst_idx)

                    # Add best
                    best_contrib = -float('inf')
                    best_idx = None
                    for idx in range(n):
                        if idx not in offspring:
                            contrib = marginal_contribution(offspring, idx)
                            if contrib > best_contrib:
                                best_contrib = contrib
                                best_idx = idx

                    if best_idx is not None:
                        offspring.add(best_idx)

            # Size correction
            while len(offspring) > k:
                smallest_contrib = float('inf')
                remove_idx = None
                for idx in offspring:
                    contrib = marginal_contribution(offspring - {idx}, idx)
                    if contrib < smallest_contrib:
                        smallest_contrib = contrib
                        remove_idx = idx

                if remove_idx is not None:
                    offspring.remove(remove_idx)

            while len(offspring) < k:
                largest_contrib = -float('inf')
                add_idx = None
                for idx in range(n):
                    if idx not in offspring:
                        contrib = marginal_contribution(offspring, idx)
                        if contrib > largest_contrib:
                            largest_contrib = contrib
                            add_idx = idx

                if add_idx is not None:
                    offspring.add(add_idx)

            offspring_hv = compute_hv(offspring)

            # Replace worst in population
            worst_idx = np.argmin(population_hv)
            if offspring_hv > population_hv[worst_idx]:
                population[worst_idx] = offspring
                population_hv[worst_idx] = offspring_hv

            # Update Pareto archive
            if offspring_hv > compute_hv(pareto_archive.get(k, set())):
                pareto_archive[k] = offspring

        # Return best solution
        best_idx = np.argmax(population_hv)
        return population[best_idx]

    # 3. Contribution-guided local swap refinement
    def local_swap_refinement(solution: Set[int], max_iter: int = 20) -> Set[int]:
        """Local refinement using contribution-guided swaps"""
        current_set = solution.copy()
        current_hv = compute_hv(current_set)

        for _ in range(max_iter):
            improved = False

            # Try swapping worst point with best external point
            worst_contrib = float('inf')
            worst_idx = None
            for idx in current_set:
                contrib = marginal_contribution(current_set - {idx}, idx)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx

            if worst_idx is None:
                break

            best_external_contrib = -float('inf')
            best_external_idx = None
            for idx in range(n):
                if idx not in current_set:
                    contrib = marginal_contribution(current_set - {worst_idx}, idx)
                    if contrib > best_external_contrib:
                        best_external_contrib = contrib
                        best_external_idx = idx

            if best_external_idx is not None:
                new_set = (current_set - {worst_idx}) | {best_external_idx}
                new_hv = compute_hv(new_set)

                if new_hv > current_hv:
                    current_set = new_set
                    current_hv = new_hv
                    improved = True

            if not improved:
                break

        return current_set

    # Main algorithm flow
    greedy_solution = greedy_initialization()
    evolved_solution = evolutionary_search(greedy_solution)
    final_solution = local_swap_refinement(evolved_solution)

    return points[list(final_solution)]
